Stop.command:
python3 -c "
import json, os, subprocess
from datetime import datetime
state_file = os.path.join(os.environ.get('HOME', '/root'), '.claude', 'of-session-state.json')
try:
    state = json.load(open(state_file)) if os.path.exists(state_file) else {}
except Exception:
    state = {}
try:
    branch = subprocess.check_output(['git','branch','--show-current'], stderr=subprocess.DEVNULL).decode().strip()
except Exception:
    branch = 'unknown'
state.update({'lastSession': datetime.utcnow().isoformat(), 'project': 'Order-flow-volume', 'branch': branch})
json.dump(state, open(state_file, 'w'), indent=2)
" 2>/dev/null; exit 0

SessionStart.command:
python3 -c "
import json, os
state_file = os.path.join(os.environ.get('HOME', '/root'), '.claude', 'of-session-state.json')
if os.path.exists(state_file):
    try:
        state = json.load(open(state_file))
        if state.get('lastSession'):
            print(f'[Order Flow] Last session: {state[\"lastSession\"]} on branch: {state.get(\"branch\", \"unknown\")}')
    except Exception:
        pass
" 2>/dev/null; exit 0
